#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, Wmax;
        scanf("%d %d", &N, &Wmax);
        int W[1001];
        int V[1001];
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &W[i], &V[i]);
        }
        int dp[1001] = {0};
        for (int i = 0; i < N; ++i) {
            int wi = W[i];
            int vi = V[i];
            for (int w = Wmax; w >= wi; --w) {
                int cand = dp[w - wi] + vi;
                if (cand > dp[w]) dp[w] = cand;
            }
        }
        printf("%d\n", dp[Wmax]);
    }
    return 0;
}

